export enum TransactionType {
  DEBIT = 'DEBIT',
  CREDIT = 'CREDIT',
}

export enum TransactionCategory {
  FOOD = 'Food & Dining',
  SHOPPING = 'Shopping',
  TRANSPORT = 'Transportation',
  UTILITIES = 'Utilities',
  ENTERTAINMENT = 'Entertainment',
  INCOME = 'Income',
  TRANSFER = 'Transfer',
}

export interface Transaction {
  id: string;
  date: string;
  merchant: string;
  amount: number;
  type: TransactionType;
  category: TransactionCategory;
  status: 'Pending' | 'Completed' | 'Failed';
  location?: string;
  cardLast4?: string;
  reviewed?: boolean;
  note?: string;
  referenceNumber?: string;
}

export interface User {
  id: string;
  name: string;
  accountNumber: string;
  balance: number;
  monthlyIncome: number;
  monthlyExpense: number;
}

export type ViewState = 
  | { view: 'HOME' }
  | { view: 'LOGIN' }
  | { view: 'DASHBOARD' }
  | { view: 'RECEIPT'; transactionId: string }
  | { view: 'RECEIPTS_INDEX' }
  | { view: 'CARDS' }
  | { view: 'STATEMENTS' }
  | { view: 'TRANSFERS' }
  | { view: 'SETTINGS' }
  | { view: 'VIDEO_GEN' }
  | { view: 'SUPPORT' };

