import React, { useState, useEffect } from 'react';
import { MOCK_TRANSACTIONS } from '../constants';
import { TransactionCategory, Transaction } from '../types';
import TransactionRow from './TransactionRow';

interface ReceiptsIndexProps {
  onNavigateReceipt: (id: string) => void;
}

const ReceiptsIndex: React.FC<ReceiptsIndexProps> = ({ onNavigateReceipt }) => {
  const [isLoading, setIsLoading] = useState(true);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterCategory, setFilterCategory] = useState<string>('All');
  const [filterType, setFilterType] = useState<string>('All');

  useEffect(() => {
    // Simulate loading
    const timer = setTimeout(() => {
      setTransactions(MOCK_TRANSACTIONS);
      setIsLoading(false);
    }, 800);
    return () => clearTimeout(timer);
  }, []);

  const handleUpdateNote = (id: string, note: string) => {
    setTransactions(prev => prev.map(tx => tx.id === id ? { ...tx, note } : tx));
  };

  const filteredTransactions = transactions.filter(tx => {
    const matchesSearch = 
        tx.merchant.toLowerCase().includes(searchQuery.toLowerCase()) || 
        tx.category.toLowerCase().includes(searchQuery.toLowerCase()) ||
        (tx.note && tx.note.toLowerCase().includes(searchQuery.toLowerCase()));

    const matchesCategory = filterCategory === 'All' || tx.category === filterCategory;
    const matchesType = filterType === 'All' || tx.type === filterType;

    return matchesSearch && matchesCategory && matchesType;
  });

  return (
    <div className="space-y-6 sm:space-y-8 animate-fade-in max-w-5xl mx-auto">
      <div>
        <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Activity</h2>
        <p className="text-slate-500 dark:text-slate-400">View your full transaction history and receipts.</p>
      </div>

      <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col min-h-[600px] overflow-hidden">

        {/* Filters Header */}
        <div className="p-4 sm:p-6 border-b border-slate-100 dark:border-slate-700 flex flex-col gap-4">
           <div className="flex flex-col sm:flex-row gap-4 justify-between">
              <div className="relative flex-1">
                 <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                   <svg className="h-4 w-4 text-slate-400" xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
                 </div>
                 <input 
                   type="text"
                   placeholder="Search transactions..."
                   value={searchQuery}
                   onChange={(e) => setSearchQuery(e.target.value)}
                   className="w-full pl-9 pr-4 py-2.5 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-brand-500 dark:text-white placeholder-slate-400 transition-colors"
                 />
              </div>
              <div className="flex gap-2 sm:gap-4 overflow-x-auto pb-1 sm:pb-0 no-scrollbar">
                 <select 
                   value={filterCategory}
                   onChange={(e) => setFilterCategory(e.target.value)}
                   className="px-4 py-2.5 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-brand-500 dark:text-white text-sm whitespace-nowrap"
                 >
                   <option value="All">All Categories</option>
                   {Object.values(TransactionCategory).map(cat => (
                     <option key={cat} value={cat}>{cat}</option>
                   ))}
                 </select>
                 <select 
                   value={filterType}
                   onChange={(e) => setFilterType(e.target.value)}
                   className="px-4 py-2.5 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-brand-500 dark:text-white text-sm whitespace-nowrap"
                 >
                   <option value="All">All Types</option>
                   <option value="DEBIT">Debit / Expense</option>
                   <option value="CREDIT">Credit / Income</option>
                 </select>
              </div>
           </div>
        </div>

        {/* Transactions List */}
        <div className="flex-1 overflow-y-auto">
           {isLoading ? (
             <div className="p-8 space-y-4 animate-pulse">
               {[1, 2, 3, 4, 5, 6].map(i => (
                 <div key={i} className="flex gap-4 items-center">
                    <div className="w-10 h-10 bg-slate-200 dark:bg-slate-700 rounded-full"></div>
                    <div className="flex-1 space-y-2">
                       <div className="h-4 w-1/3 bg-slate-200 dark:bg-slate-700 rounded"></div>
                       <div className="h-3 w-1/4 bg-slate-200 dark:bg-slate-700 rounded"></div>
                    </div>
                    <div className="h-4 w-16 bg-slate-200 dark:bg-slate-700 rounded"></div>
                 </div>
               ))}
             </div>
           ) : filteredTransactions.length > 0 ? (
             <div className="divide-y divide-slate-100 dark:divide-slate-700">
               {/* Desktop Header */}
               <div className="hidden md:grid grid-cols-12 gap-4 px-4 py-3 bg-slate-50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-700 text-[10px] font-semibold text-slate-500 uppercase tracking-wider items-center select-none sticky top-0 z-10">
                   <div className="col-span-1"></div>
                   <div className="col-span-3">Transaction</div>
                   <div className="col-span-2">Category</div>
                   <div className="col-span-2">Method</div>
                   <div className="col-span-2">Note</div>
                   <div className="col-span-1">Date</div>
                   <div className="col-span-1 text-right">Amt</div>
               </div>

               {filteredTransactions.map(tx => (
                 <TransactionRow 
                   key={tx.id} 
                   transaction={tx} 
                   onClick={() => onNavigateReceipt(tx.id)}
                   isSelected={false}
                   onUpdateNote={handleUpdateNote}
                 />
               ))}
             </div>
           ) : (
             <div className="flex flex-col items-center justify-center h-full p-12 text-slate-500 dark:text-slate-400">
               <div className="w-16 h-16 bg-slate-100 dark:bg-slate-900 rounded-full flex items-center justify-center mb-4">
                 <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="opacity-50"><circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line></svg>
               </div>
               <h3 className="font-bold text-lg text-slate-900 dark:text-white mb-1">No transactions found</h3>
               <p className="text-sm">Try adjusting your filters or search terms.</p>
             </div>
           )}
        </div>

        {/* Footer Stats */}
        <div className="bg-slate-50 dark:bg-slate-900/50 border-t border-slate-100 dark:border-slate-700 p-4 text-xs text-slate-500 dark:text-slate-400 flex justify-between items-center">
           <span>Showing {filteredTransactions.length} transactions</span>
           <button className="text-brand-600 hover:text-brand-700 font-bold">Export to CSV</button>
        </div>
      </div>
    </div>
  );
};

