import React, { useState } from 'react';
import { Transaction, TransactionType, TransactionCategory } from '../types';

interface TransfersProps {
  onTransaction: (tx: Transaction) => void;
}

const Transfers: React.FC<TransfersProps> = ({ onTransaction }) => {
  const [step, setStep] = useState(1);
  const [transferMode, setTransferMode] = useState<'internal' | 'external'>('internal');
  const [amount, setAmount] = useState('');
  const [recipient, setRecipient] = useState('');

  // External Transfer Fields
  const [bankName, setBankName] = useState('');
  const [routingNumber, setRoutingNumber] = useState('');
  const [accountNumber, setAccountNumber] = useState('');

  const [isProcessing, setIsProcessing] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);

  const linkedAccounts = [
    { id: '1', name: 'Main Savings', balance: 12450.50, color: 'bg-brand-500' },
    { id: '2', name: 'Investment Port.', balance: 85200.00, color: 'bg-emerald-500' },
    { id: '3', name: 'Emergency Fund', balance: 5000.00, color: 'bg-amber-500' }
  ];

  const handleModeSelect = (mode: 'internal' | 'external') => {
    setTransferMode(mode);
    setStep(2);
  };

  const handleTransfer = (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);

    // Simulate API delay
    setTimeout(() => {
      const newTx: Transaction = {
        id: `tx_${Date.now()}`,
        date: new Date().toISOString(),
        merchant: transferMode === 'external' ? `Transfer to ${recipient} (${bankName})` : `Transfer to ${recipient}`,
        amount: parseFloat(amount),
        type: TransactionType.DEBIT,
        category: TransactionCategory.TRANSFER,
        status: 'Completed',
        location: 'Mobile App',
        note: transferMode === 'external' ? `External Transfer to ${bankName} •••• ${accountNumber.slice(-4)}` : 'Internal Transfer',
      };

      onTransaction(newTx);
      setIsProcessing(false);
      setShowSuccess(true);

      setTimeout(() => {
        setShowSuccess(false);
        setStep(1);
        // Reset form
        setAmount('');
        setRecipient('');
        setBankName('');
        setRoutingNumber('');
        setAccountNumber('');
      }, 3000);
