        </div>
        <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-2">Transfer Successful!</h2>
        <p className="text-slate-500 dark:text-slate-400 font-medium">Funds are on their way to {recipient || 'your account'}.</p>
