    <div className="space-y-6 sm:space-y-8 animate-fade-in pb-12">
      <div className="px-1 sm:px-0">
        <h2 className="text-xl sm:text-2xl font-black text-slate-900 dark:text-white">Transfers</h2>
        <p className="text-sm sm:text-base text-slate-500 dark:text-slate-400 font-medium">Move money between accounts or send to others.</p>
      </div>

      <div className="grid lg:grid-cols-3 gap-6 sm:gap-8">
        {/* Transfer Form Section */}
