                  <div className={`w-3 h-3 rounded-full shrink-0 ${acc.color} group-hover:scale-125 transition-transform`}></div>
                  <div className="text-left min-w-0">
                    <div className="text-sm font-black text-slate-900 dark:text-white truncate">{acc.name}</div>
                    <div className="text-[10px] font-bold text-slate-400 mt-0.5 tracking-tight">${acc.balance.toLocaleString()} available</div>
