  const [username, setUsername] = useState('jenifer.jackson');
  const [password, setPassword] = useState('');

  const biometricsAvailable = !!(window.PublicKeyCredential && window.navigator.credentials);
  const hasRegisteredBiometrics = localStorage.getItem('trustbank_device_registered') === 'true';

  const handlePasswordLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!username || !password) {
      setAuthError('Please enter both username and password.');
      return;
    }

    setIsLoading(true);
    setAuthError(null);

    // Systematic Auth Simulation
    setTimeout(() => {
      setIsLoading(false);
      const is2FAEnabled = localStorage.getItem('is2FAEnabled') === 'true';
      if (is2FAEnabled) {
        setShow2FA(true);
      } else {
        onLogin();
      }
    }, 1200);
  };

  const handleBiometricLogin = async () => {
    if (!biometricsAvailable || !hasRegisteredBiometrics) {
      setAuthError('Biometric authentication is not set up on this device.');
      return;
    }

    setAuthError(null);
    setIsAuthenticating(true);

    try {
      // Production-standard WebAuthn Retrieval Simulation
      // In a real environment, 'challenge' comes from the server
      const publicKeyOptions: PublicKeyCredentialRequestOptions = {
        challenge: Uint8Array.from("trustbank_secure_challenge_" + Date.now(), c => c.charCodeAt(0)),
        timeout: 60000,
        userVerification: "required",
        rpId: window.location.hostname || "localhost",
      };

      // Systematic browser API call
      // Note: This might trigger a real system prompt or fail in specific iframe/sandbox restricted environments
      try {
        const credential = await navigator.credentials.get({
          publicKey: publicKeyOptions
        });

        if (credential) {
          // Success: Simulate server-side verification of the signature
          setTimeout(() => {
            setIsAuthenticating(false);
            onLogin();
          }, 800);
        }
