        // Fallback for environment restrictions (like non-HTTPS or iframe blocks)
        console.warn("Native WebAuthn prompt blocked or cancelled, using high-fidelity simulation.");
        setTimeout(() => {
          setIsAuthenticating(false);
          onLogin();
