import React, { useState } from 'react';
import { TransactionCategory, Transaction, TransactionType, User } from '../types';
import TransactionRow from './TransactionRow';
import SpendingChart from './SpendingChart';

interface DashboardProps {
  user: User;
  transactions: Transaction[];
  isLoadingData: boolean;
  onTransaction: (tx: Transaction) => void;
  onUpdateNote: (id: string, note: string) => void;
  onNavigateReceipt: (id: string) => void;
  onViewAll?: () => void;
  isDarkMode?: boolean;
}

const DashboardSkeleton = () => (
  <div className="space-y-8 animate-pulse">
    <div className="flex flex-col md:flex-row justify-between gap-4">
      <div className="space-y-2">
        <div className="h-8 w-64 bg-slate-200 dark:bg-slate-700 rounded-lg"></div>
        <div className="h-4 w-48 bg-slate-200 dark:bg-slate-700 rounded-lg"></div>
      </div>
      <div className="flex gap-3">
        <div className="h-10 w-28 bg-slate-200 dark:bg-slate-700 rounded-lg"></div>
        <div className="h-10 w-32 bg-slate-200 dark:bg-slate-700 rounded-lg"></div>
      </div>
    </div>
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
      <div className="h-48 bg-slate-200 dark:bg-slate-700 rounded-3xl"></div>
      <div className="h-48 bg-slate-200 dark:bg-slate-700 rounded-3xl"></div>
      <div className="h-48 bg-slate-200 dark:bg-slate-700 rounded-3xl hidden lg:block"></div>
    </div>
  </div>
);

const Dashboard: React.FC<DashboardProps> = ({ 
  user, 
  transactions, 
  isLoadingData, 
  onTransaction, 
  onUpdateNote,
  onNavigateReceipt, 
  onViewAll, 
  isDarkMode 
}) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [filterCategory, setFilterCategory] = useState<string>('All');
  const [selectedTxIds, setSelectedTxIds] = useState<Set<string>>(new Set());
  const [sortConfig, setSortConfig] = useState<{ key: 'merchant' | 'date' | 'amount'; direction: 'asc' | 'desc' }>({ 
    key: 'date', 
    direction: 'desc' 
  });

  const [activeModal, setActiveModal] = useState<'ADD_MONEY' | 'TRANSFER' | null>(null);
  const [amount, setAmount] = useState('');
  const [recipient, setRecipient] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');

  const handleSelectTx = (id: string) => {
    const newSelected = new Set(selectedTxIds);
    if (newSelected.has(id)) newSelected.delete(id);
    else newSelected.add(id);
    setSelectedTxIds(newSelected);
  };

  const handleSelectAll = () => {
    if (selectedTxIds.size === filteredTransactions.length) {
      setSelectedTxIds(new Set());
    } else {
      setSelectedTxIds(new Set(filteredTransactions.map(tx => tx.id)));
    }
  };

  const handleCloseModal = () => {
    setActiveModal(null);
    setAmount('');
    setRecipient('');
    setSuccessMsg('');
    setIsProcessing(false);
  };

  const handleDeposit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || isNaN(Number(amount))) return;
    setIsProcessing(true);
    setTimeout(() => {
      onTransaction({
        id: `tx_${Date.now()}`,
        date: new Date().toISOString(),
        merchant: 'External Bank Deposit',
        amount: parseFloat(amount),
        type: TransactionType.CREDIT,
        category: TransactionCategory.INCOME,
        status: 'Completed',
        location: 'Secure Transfer',
      });
      setIsProcessing(false);
      setSuccessMsg('Funds deposited!');
      setTimeout(() => handleCloseModal(), 1500);
    }, 1500);
  };

  const handleTransfer = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || isNaN(Number(amount)) || !recipient) return;
    setIsProcessing(true);
    setTimeout(() => {
      onTransaction({
        id: `tx_${Date.now()}`,
        date: new Date().toISOString(),
        merchant: `Transfer to ${recipient}`,
        amount: parseFloat(amount),
        type: TransactionType.DEBIT,
        category: TransactionCategory.TRANSFER,
        status: 'Completed',
        location: 'TrustBank Network',
      });
      setIsProcessing(false);
      setSuccessMsg('Transfer sent!');
      setTimeout(() => handleCloseModal(), 1500);
    }, 1500);
  };

  const handleSort = (key: 'merchant' | 'date' | 'amount') => {
    setSortConfig(current => ({
      key,
      direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  const filteredTransactions = transactions.filter(tx => {
