import React, { useState } from 'react';
import { CURRENT_USER } from '../constants';

interface SettingsProps {
  onNotify?: (msg: string) => void;
}

const Settings: React.FC<SettingsProps> = ({ onNotify }) => {
  const [isSaving, setIsSaving] = useState(false);
  const [isRegistering, setIsRegistering] = useState(false);
  const [formData, setFormData] = useState({
    name: CURRENT_USER.name,
    email: 'jenifer.jackson@trustbank.com',
    phone: '+1 (555) 123-4567'
  });
  const [successMessage, setSuccessMessage] = useState('');

  // 2FA & Biometric State
  const [is2FAEnabled, setIs2FAEnabled] = useState(() => localStorage.getItem('is2FAEnabled') === 'true');
  const [isDeviceRegistered, setIsDeviceRegistered] = useState(() => localStorage.getItem('trustbank_device_registered') === 'true');

  const handle2FAToggle = () => {
    const newValue = !is2FAEnabled;
    setIs2FAEnabled(newValue);
    localStorage.setItem('is2FAEnabled', String(newValue));
    onNotify?.(newValue ? "2FA Enabled" : "2FA Disabled");
  };

  const handleDeviceRegistration = async () => {
    if (isDeviceRegistered) {
      if (confirm('Are you sure you want to remove biometric trust for this device?')) {
        localStorage.removeItem('trustbank_device_registered');
        setIsDeviceRegistered(false);
        onNotify?.("Device removed from trusted list");
      }
      return;
    }

    setIsRegistering(true);

    try {
      // Production-standard WebAuthn Registration Simulation
      const publicKeyOptions: PublicKeyCredentialCreationOptions = {
        challenge: Uint8Array.from("trustbank_registration_challenge_" + Date.now(), c => c.charCodeAt(0)),
        rp: { name: "TrustBank Secure", id: window.location.hostname || "localhost" },
        user: {
          id: Uint8Array.from(CURRENT_USER.id, c => c.charCodeAt(0)),
          name: CURRENT_USER.name,
          displayName: CURRENT_USER.name
        },
        pubKeyCredParams: [{ alg: -7, type: "public-key" }], // ES256
        timeout: 60000,
        attestation: "direct",
        authenticatorSelection: { userVerification: "required" }
      };

      try {
        const credential = await navigator.credentials.create({
          publicKey: publicKeyOptions
        });

        if (credential) {
          localStorage.setItem('trustbank_device_registered', 'true');
          setIsDeviceRegistered(true);
          setSuccessMessage('Device registered successfully!');
          setTimeout(() => setSuccessMessage(''), 3000);
          onNotify?.("Device successfully trusted");
        }
      } catch (e) {
        // Fallback simulation for restricted environments
        console.warn("Native registration prompt unavailable, simulating success.");
        setTimeout(() => {
          localStorage.setItem('trustbank_device_registered', 'true');
          setIsDeviceRegistered(true);
          setSuccessMessage('Device trusted via Simulation.');
          setTimeout(() => setSuccessMessage(''), 3000);
          setIsRegistering(false);
          onNotify?.("Device successfully trusted");
        }, 1500);
        return;
      }
    } catch (err) {
      alert('Registration failed. Please ensure your device supports biometric authentication.');
    } finally {
      setIsRegistering(false);
    }
  };

  const handleSave = () => {
    setIsSaving(true);
    setSuccessMessage('');
    setTimeout(() => {
      setIsSaving(false);
      setSuccessMessage('Profile updated successfully!');
      setTimeout(() => setSuccessMessage(''), 3000);
      onNotify?.("Profile changes saved");
    }, 1200);
  };

  return (
    <div className="space-y-8 animate-fade-in max-w-5xl mx-auto pb-12">
      <div className="px-1">
        <h2 className="text-3xl font-black text-slate-900 dark:text-white tracking-tight">Security & Preferences</h2>
        <p className="text-slate-500 dark:text-slate-400 font-medium">Manage your account settings and security protocols.</p>
      </div>

      <div className="grid lg:grid-cols-3 gap-8">
        {/* Profile Card */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white dark:bg-slate-900 rounded-[2rem] shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden">
            <div className="p-8 sm:p-10 border-b border-slate-100 dark:border-slate-800">
               <div className="flex justify-between items-center mb-8">
                 <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-widest text-[10px]">Personal Information</h3>
                 {successMessage && <span className="text-green-600 text-xs font-bold animate-pulse">{successMessage}</span>}
               </div>

               <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="space-y-1.5">
                     <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Full Name</label>
                     <input 
                       type="text" 
                       value={formData.name}
                       onChange={(e) => setFormData({...formData, name: e.target.value})}
                       className="w-full px-5 py-3.5 rounded-2xl border border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-white focus:border-brand-500 outline-none transition-all font-semibold"
                     />
                  </div>
                  <div className="space-y-1.5">
                     <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Email Address</label>
                     <input 
                       type="email" 
                       value={formData.email}
                       onChange={(e) => setFormData({...formData, email: e.target.value})}
                       className="w-full px-5 py-3.5 rounded-2xl border border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-white focus:border-brand-500 outline-none transition-all font-semibold"
                     />
                  </div>
                  <div className="space-y-1.5">
                     <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Phone Number</label>
                     <input 
                       type="tel" 
                       value={formData.phone}
                       onChange={(e) => setFormData({...formData, phone: e.target.value})}
                       className="w-full px-5 py-3.5 rounded-2xl border border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-white focus:border-brand-500 outline-none transition-all font-semibold"
                     />
                  </div>
                  <div className="flex items-end pt-4 md:pt-0">
                     <button 
                      onClick={handleSave}
                      disabled={isSaving}
                      className="w-full sm:w-auto px-10 py-4 bg-brand-600 hover:bg-brand-700 disabled:opacity-50 text-white font-black rounded-2xl transition-all shadow-lg shadow-brand-500/20 active:scale-95"
                     >
                        {isSaving ? 'Syncing...' : 'Update Records'}
                     </button>
                  </div>
               </div>
            </div>

            <div className="p-8 sm:p-10 bg-slate-50/50 dark:bg-slate-950/30">
               <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-6">Security Protocols</h4>
               <div className="space-y-6">
                  <div className="flex items-center justify-between p-6 bg-white dark:bg-slate-900 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm">
                     <div className="flex items-center gap-4">
                        <div className="w-12 h-12 bg-purple-100 dark:bg-purple-900/30 text-purple-600 rounded-2xl flex items-center justify-center shrink-0">
                           <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg>
                        </div>
                        <div>
                           <h4 className="font-bold text-slate-900 dark:text-white">Multi-Factor Authentication</h4>
                           <p className="text-xs text-slate-500 mt-0.5">Mandatory verification on new logins.</p>
                        </div>
                     </div>
                     <label className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" className="sr-only peer" checked={is2FAEnabled} onChange={handle2FAToggle} />
