  const [targetCurrency, setTargetCurrency] = useState('EUR');

  // Savings Goals State
  const [goals, setGoals] = useState([
    { id: 1, name: 'Emergency Fund', target: 20000, current: 12450, color: 'bg-emerald-500' },
