    setTransactions(prev => [tx, ...prev]);
    if (tx.type === TransactionType.DEBIT) {
      setUser(prev => ({ ...prev, balance: prev.balance - tx.amount }));
    } else if (tx.type === TransactionType.CREDIT) {
      setUser(prev => ({ ...prev, balance: prev.balance + tx.amount }));
    }
    showNotification("Transaction completed successfully");
  };

