              </div>
              <div>
                <h3 className="text-lg font-black text-red-700 dark:text-red-400">Account On Hold</h3>
                <p className="text-sm font-medium text-red-600/80 dark:text-red-400/80 max-w-xl mt-1">
                  Your account has been temporarily frozen due to outstanding re-issuing charges. 
                  Transfers and withdrawals are restricted until the balance is cleared.
                </p>
                <div className="mt-3 flex items-center gap-2 text-xs font-black uppercase tracking-widest text-red-500">
                  <span>Due Amount:</span>
                  <span className="text-lg text-red-700 dark:text-red-400">${user.dueCharges.toFixed(2)}</span>
                </div>
              </div>
            </div>
            <button 
              onClick={handlePaymentClick}
              disabled={isPayingCharges}
              className="w-full sm:w-auto px-8 py-3 bg-red-600 hover:bg-red-700 text-white font-black rounded-xl shadow-xl shadow-red-500/20 active:scale-95 transition-all flex items-center justify-center gap-2"
            >
              {isPayingCharges ? (
                <>
                  <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                  Processing...
                </>
              ) : (
                `Pay $${user.dueCharges}`
              )}
            </button>
          </div>
        </div>
      )}

      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-xl sm:text-2xl font-bold text-slate-900 dark:text-white">Account Overview</h2>
          <p className="text-sm text-slate-500 dark:text-slate-400">Manage your liquid assets and daily expenses.</p>
