                              onChange={(e) => setBankName(e.target.value)}
                              placeholder="e.g. Chase, Wells Fargo"
                              className="w-full px-5 py-4 rounded-2xl border border-slate-200 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white outline-none focus:ring-4 focus:ring-brand-500/10 font-medium transition-all"
                            />
                          </div>
                          <div>
                            <label className="block text-xs font-black uppercase tracking-widest text-slate-400 mb-2">Routing Number</label>
                            <input 
                              type="text" 
                              value={routingNumber}
                              onChange={(e) => setRoutingNumber(e.target.value)}
                              placeholder="9 Digits"
                              className="w-full px-5 py-4 rounded-2xl border border-slate-200 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white outline-none focus:ring-4 focus:ring-brand-500/10 font-medium transition-all"
                            />
                          </div>
                        </div>
                        <div>
                          <label className="block text-xs font-black uppercase tracking-widest text-slate-400 mb-2">Account Number</label>
                          <input 
                            type="text" 
                            value={accountNumber}
                            onChange={(e) => setAccountNumber(e.target.value)}
                            placeholder="Account Number"
                            className="w-full px-5 py-4 rounded-2xl border border-slate-200 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white outline-none focus:ring-4 focus:ring-brand-500/10 font-medium transition-all"
                          />
                        </div>
                      </>
                    )}

                    <div>
                      <label className="block text-xs font-black uppercase tracking-widest text-slate-400 mb-2">Amount ($)</label>
                      <input 
                        type="number" 
                        value={amount}
                        onChange={(e) => setAmount(e.target.value)}
                        placeholder="0.00"
                        className="w-full px-5 py-4 rounded-2xl border border-slate-200 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white outline-none focus:ring-4 focus:ring-brand-500/10 font-black text-2xl transition-all"
                      />
                    </div>
                  </div>

                  <div className="flex flex-col sm:flex-row gap-3 pt-6">
                    <button type="button" onClick={() => setStep(1)} className="order-2 sm:order-1 flex-1 py-4 bg-slate-100 dark:bg-slate-900 text-slate-600 dark:text-slate-400 rounded-2xl font-black transition-colors hover:bg-slate-200 dark:hover:bg-slate-800">Cancel</button>
                    <button type="button" onClick={() => setStep(3)} className="order-1 sm:order-2 flex-1 py-4 bg-brand-600 text-white rounded-2xl font-black shadow-xl shadow-brand-500/20 active:scale-95 transition-transform">Continue</button>
                  </div>
                </div>
              )}

              {step === 3 && (
                <div className="animate-fade-in space-y-8">
                  <h3 className="text-lg font-black text-slate-900 dark:text-white">Review Transaction</h3>
                  <div className="bg-slate-50 dark:bg-slate-900/50 p-6 sm:p-8 rounded-[2rem] border border-dashed border-slate-200 dark:border-slate-700 space-y-6">
                    <div className="flex justify-between items-center pb-4 border-b border-slate-100 dark:border-slate-800">
                      <span className="text-slate-400 text-xs font-black uppercase tracking-widest">Recipient</span>
                      <span className="font-black text-slate-900 dark:text-white truncate max-w-[150px]">{recipient || 'N/A'}</span>
                    </div>

                    {transferMode === 'external' && (
                      <>
                        <div className="flex justify-between items-center pb-4 border-b border-slate-100 dark:border-slate-800">
                           <span className="text-slate-400 text-xs font-black uppercase tracking-widest">Bank</span>
                           <span className="font-black text-slate-900 dark:text-white truncate max-w-[150px]">{bankName}</span>
                        </div>
                        <div className="flex justify-between items-center pb-4 border-b border-slate-100 dark:border-slate-800">
                           <span className="text-slate-400 text-xs font-black uppercase tracking-widest">Account</span>
                           <span className="font-black text-slate-900 dark:text-white truncate max-w-[150px]">•••• {accountNumber.slice(-4)}</span>
                        </div>
                      </>
                    )}

                    <div className="flex justify-between items-center py-4 border-b border-slate-100 dark:border-slate-800">
                      <span className="text-slate-400 text-xs font-black uppercase tracking-widest">Amount</span>
                      <span className="font-black text-2xl text-slate-900 dark:text-white">${parseFloat(amount || '0').toLocaleString('en-US', { minimumFractionDigits: 2 })}</span>
                    </div>
                    <div className="flex justify-between items-center pt-2 text-[10px] text-brand-600 dark:text-brand-400 font-black uppercase tracking-widest">
                      <span>Delivery Method</span>
                      <span className="px-2 py-0.5 bg-brand-100 dark:bg-brand-900/30 rounded">
                        {transferMode === 'external' ? 'Standard ACH (1-2 Days)' : 'Instant'}
                      </span>
                    </div>
                  </div>
                  <div className="flex flex-col sm:flex-row gap-3">
                    <button type="button" onClick={() => setStep(2)} className="order-2 sm:order-1 flex-1 py-4 bg-slate-100 dark:bg-slate-900 text-slate-600 dark:text-slate-400 rounded-2xl font-black transition-colors hover:bg-slate-200 dark:hover:bg-slate-800">Modify</button>
                    <button 
                      type="submit" 
                      disabled={isProcessing}
                      className="order-1 sm:order-2 flex-1 py-4 bg-brand-600 text-white rounded-2xl font-black shadow-xl shadow-brand-500/30 flex items-center justify-center gap-3 active:scale-95 transition-transform"
                    >
                      {isProcessing ? <div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Confirm & Transfer'}
                    </button>
                  </div>
                </div>
              )}
            </form>
          </div>
        </div>

        {/* Sidebar Linked Accounts - stacks on mobile */}
        <div className="space-y-6">
          <h3 className="text-sm font-black uppercase tracking-widest text-slate-400 px-1">Frequent Links</h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-1 gap-4">
            {linkedAccounts.map(acc => (
              <button key={acc.id} className="p-5 bg-white dark:bg-slate-800 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-700 flex items-center justify-between hover:bg-slate-50 dark:hover:bg-slate-700 transition-all active:scale-[0.98] group">
                <div className="flex items-center gap-4 min-w-0">
                  <div className={`w-3 h-3 rounded-full shrink-0 ${acc.color} group-hover:scale-125 transition-transform`}></div>
                  <div className="text-left min-w-0">
                    <div className="text-sm font-black text-slate-900 dark:text-white truncate">{acc.name}</div>
                    <div className="text-[10px] font-bold text-slate-400 mt-0.5 tracking-tight">${acc.balance.toLocaleString()} available</div>
                  </div>
                </div>
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="text-slate-200 group-hover:text-brand-500 transition-colors shrink-0 ml-2"><polyline points="9 18 15 12 9 6"/></svg>
              </button>
            ))}
            <button className="p-5 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl flex items-center justify-center gap-2 text-slate-400 hover:text-brand-600 hover:border-brand-600 hover:bg-brand-50/10 transition-all text-xs font-black uppercase tracking-wider">
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><path d="M12 8v8"/><path d="M8 12h8"/></svg>
              Add Connection
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Transfers;

export enum TransactionType {
  DEBIT = 'DEBIT',
  CREDIT = 'CREDIT',
}

export enum TransactionCategory {
  FOOD = 'Food & Dining',
  SHOPPING = 'Shopping',
  TRANSPORT = 'Transportation',
  UTILITIES = 'Utilities',
  ENTERTAINMENT = 'Entertainment',
  INCOME = 'Income',
  TRANSFER = 'Transfer',
  GOAL = 'Savings Goal',
  FEES = 'Bank Fees',
}

export interface Transaction {
  id: string;
  date: string;
  merchant: string;
  amount: number;
  type: TransactionType;
  category: TransactionCategory;
  status: 'Pending' | 'Completed' | 'Failed';
  location?: string;
  cardLast4?: string;
  reviewed?: boolean;
  note?: string;
  referenceNumber?: string;
}

export interface User {
  id: string;
  name: string;
  accountNumber: string;
  balance: number;
  monthlyIncome: number;
  monthlyExpense: number;
  accountStatus: 'Active' | 'On Hold';
  dueCharges: number;
}

export type ViewType = 
  | 'HOME' 
  | 'LOGIN' 
  | 'DASHBOARD' 
  | 'PAYMENT_REQUIRED'
  | 'RECEIPT' 
  | 'RECEIPTS_INDEX' 
  | 'CARDS' 
  | 'STATEMENTS' 
  | 'TRANSFERS' 
  | 'TOOLS'
  | 'SETTINGS' 
  | 'SUPPORT';

export type ViewState = 
  | { view: Exclude<ViewType, 'RECEIPT'> }
  | { view: 'RECEIPT'; transactionId: string };

import React, { useState } from 'react';
import { TransactionCategory, Transaction, TransactionType, User } from '../types';
import TransactionRow from './TransactionRow';
import SpendingChart from './SpendingChart';

interface DashboardProps {
  user: User;
  transactions: Transaction[];
  isLoadingData: boolean;
  onTransaction: (tx: Transaction) => void;
  onPayChargesRedirect: () => void;
  onUpdateNote: (id: string, note: string) => void;
  onNavigateReceipt: (id: string) => void;
  onViewAll?: () => void;
  isDarkMode?: boolean;
}

const DashboardSkeleton = () => (
  <div className="space-y-8 animate-pulse">
    <div className="flex flex-col md:flex-row justify-between gap-4">
      <div className="space-y-2">
        <div className="h-8 w-64 bg-slate-200 dark:bg-slate-700 rounded-lg"></div>
        <div className="h-4 w-48 bg-slate-200 dark:bg-slate-700 rounded-lg"></div>
      </div>
      <div className="flex gap-3">
        <div className="h-10 w-28 bg-slate-200 dark:bg-slate-700 rounded-lg"></div>
        <div className="h-10 w-32 bg-slate-200 dark:bg-slate-700 rounded-lg"></div>
      </div>
    </div>
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
      <div className="h-48 bg-slate-200 dark:bg-slate-700 rounded-3xl"></div>
      <div className="h-48 bg-slate-200 dark:bg-slate-700 rounded-3xl"></div>
      <div className="h-48 bg-slate-200 dark:bg-slate-700 rounded-3xl hidden lg:block"></div>
    </div>
  </div>
);

const Dashboard: React.FC<DashboardProps> = ({ 
  user, 
  transactions, 
  isLoadingData, 
  onTransaction, 
  onPayChargesRedirect,
  onUpdateNote,
  onNavigateReceipt, 
  onViewAll, 
  isDarkMode 
}) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [filterCategory, setFilterCategory] = useState<string>('All');
  const [selectedTxIds, setSelectedTxIds] = useState<Set<string>>(new Set());
  const [sortConfig, setSortConfig] = useState<{ key: 'merchant' | 'date' | 'amount'; direction: 'asc' | 'desc' }>({ 
    key: 'date', 
    direction: 'desc' 
  });

  const [activeModal, setActiveModal] = useState<'ADD_MONEY' | 'TRANSFER' | null>(null);
  const [amount, setAmount] = useState('');
  const [recipient, setRecipient] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');

  const isOnHold = user.accountStatus === 'On Hold';

  const handleSelectTx = (id: string) => {
    const newSelected = new Set(selectedTxIds);
    if (newSelected.has(id)) newSelected.delete(id);
    else newSelected.add(id);
    setSelectedTxIds(newSelected);
  };

  const handleSelectAll = () => {
    if (selectedTxIds.size === filteredTransactions.length) {
      setSelectedTxIds(new Set());
    } else {
      setSelectedTxIds(new Set(filteredTransactions.map(tx => tx.id)));
    }
  };

  const handleCloseModal = () => {
    setActiveModal(null);
    setAmount('');
    setRecipient('');
    setSuccessMsg('');
    setIsProcessing(false);
  };

  const handleDeposit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || isNaN(Number(amount))) return;
    setIsProcessing(true);
    setTimeout(() => {
      onTransaction({
        id: `tx_${Date.now()}`,
        date: new Date().toISOString(),
        merchant: 'External Bank Deposit',
        amount: parseFloat(amount),
        type: TransactionType.CREDIT,
        category: TransactionCategory.INCOME,
        status: 'Completed',
        location: 'Secure Transfer',
      });
      setIsProcessing(false);
      setSuccessMsg('Funds deposited!');
      setTimeout(() => handleCloseModal(), 1500);
    }, 1500);
  };

  const handleTransfer = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || isNaN(Number(amount)) || !recipient) return;
    if (isOnHold) return; // double check protection

    setIsProcessing(true);
    setTimeout(() => {
      onTransaction({
        id: `tx_${Date.now()}`,
        date: new Date().toISOString(),
        merchant: `Transfer to ${recipient}`,
        amount: parseFloat(amount),
        type: TransactionType.DEBIT,
        category: TransactionCategory.TRANSFER,
        status: 'Completed',
        location: 'TrustBank Network',
      });
      setIsProcessing(false);
      setSuccessMsg('Transfer sent!');
      setTimeout(() => handleCloseModal(), 1500);
    }, 1500);
  };

  const handleSort = (key: 'merchant' | 'date' | 'amount') => {
    setSortConfig(current => ({
      key,
      direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  const filteredTransactions = transactions.filter(tx => {
    const matchesSearch = tx.merchant.toLowerCase().includes(searchQuery.toLowerCase()) || 
                          (tx.note && tx.note.toLowerCase().includes(searchQuery.toLowerCase()));
    const matchesCategory = filterCategory === 'All' || tx.category === filterCategory;
    return matchesSearch && matchesCategory;
  });

  const sortedTransactions = [...filteredTransactions].sort((a, b) => {
    const { key, direction } = sortConfig;
    let comparison = key === 'date' ? new Date(a.date).getTime() - new Date(b.date).getTime() :
                    key === 'amount' ? a.amount - b.amount : a.merchant.localeCompare(b.merchant);
    return direction === 'asc' ? comparison : -comparison;
  });

  if (isLoadingData) return <DashboardSkeleton />;

  return (
    <div className="space-y-6 sm:space-y-8 animate-fade-in relative pb-10">

      {/* Account Hold Banner - Compact Version */}
      {isOnHold && (
        <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-2xl p-4 animate-shake shadow-sm">
          <div className="flex items-center justify-between gap-3">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-red-100 dark:bg-red-900/50 text-red-600 dark:text-red-400 rounded-xl flex items-center justify-center shrink-0">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
              </div>
              <div className="flex flex-col sm:flex-row sm:items-baseline gap-1 sm:gap-3">
                <h3 className="text-base font-black text-red-700 dark:text-red-400">Action Required</h3>
                <p className="text-xs font-semibold text-red-600/80 dark:text-red-400/80">
                   Outstanding charges of <span className="font-bold underline">${user.dueCharges.toFixed(2)}</span> pending.
                </p>
              </div>
            </div>
            <button 
              onClick={onPayChargesRedirect}
              className="px-4 py-2 bg-red-600 hover:bg-red-700 text-white text-xs font-black rounded-lg shadow-md shadow-red-500/20 active:scale-95 transition-all whitespace-nowrap"
            >
              Pay Now
            </button>
          </div>
        </div>
      )}

      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-xl sm:text-2xl font-bold text-slate-900 dark:text-white">Account Overview</h2>
          <p className="text-sm text-slate-500 dark:text-slate-400">Manage your liquid assets and daily expenses.</p>
        </div>
        <div className="flex gap-2 sm:gap-3">
           <button onClick={() => setActiveModal('ADD_MONEY')} className="flex-1 sm:flex-none bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 px-4 py-2 rounded-xl text-sm font-bold hover:bg-slate-50 transition-colors shadow-sm">Add Money</button>
           <button 
             onClick={() => setActiveModal('TRANSFER')} 
             disabled={isOnHold}
             className={`flex-1 sm:flex-none px-4 py-2 rounded-xl text-sm font-bold shadow-lg transition-all ${
               isOnHold 
                 ? 'bg-slate-100 dark:bg-slate-800 text-slate-400 cursor-not-allowed shadow-none' 
                 : 'bg-brand-600 text-white hover:bg-brand-700 shadow-brand-500/20'
             }`}
           >
             {isOnHold ? 'Transfers Locked' : 'Send Transfer'}
           </button>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        <div className={`rounded-[2.5rem] p-8 text-white shadow-2xl relative overflow-hidden flex flex-col justify-between group h-64 transition-all hover:scale-[1.01] ${isOnHold ? 'bg-slate-800 grayscale-[0.5]' : 'bg-gradient-to-br from-brand-600 to-indigo-700'}`}>
          <div className="absolute top-0 right-0 p-32 bg-white/10 rounded-full transform translate-x-12 -translate-y-12 blur-3xl"></div>
          <div>
            <p className={`${isOnHold ? 'text-slate-400' : 'text-brand-100'} text-xs font-black uppercase tracking-widest mb-2`}>Available Balance</p>
            <h3 className="text-4xl font-black tracking-tighter">${user.balance.toLocaleString('en-US', { minimumFractionDigits: 2 })}</h3>
          </div>
          <div className="flex justify-between items-end">
             <div>
                <p className={`${isOnHold ? 'text-slate-500' : 'text-brand-200'} text-[10px] uppercase tracking-widest mb-1`}>Account Number</p>
                <p className="font-mono text-sm tracking-widest">{user.accountNumber}</p>
             </div>
             <div className="w-10 h-7 bg-white/20 rounded border border-white/30 flex items-center justify-center">
                <div className="w-5 h-3 border border-white/50 rounded-sm"></div>
             </div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-8 rounded-[2.5rem] shadow-sm border border-slate-100 dark:border-slate-700">
           <p className="text-slate-400 text-xs font-black uppercase tracking-widest mb-4">Inflow</p>
           <h3 className="text-3xl font-black text-slate-900 dark:text-white mb-2">${user.monthlyIncome.toLocaleString()}</h3>
           <p className="text-green-600 text-xs font-bold flex items-center gap-1">
             <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="23 6 13.5 15.5 8.5 10.5 1 18"/><polyline points="17 6 23 6 23 12"/></svg>
             +8.2% Monthly Increase
           </p>
        </div>

        <div className="bg-white dark:bg-slate-800 p-8 rounded-[2.5rem] shadow-sm border border-slate-100 dark:border-slate-700">
           <p className="text-slate-400 text-xs font-black uppercase tracking-widest mb-4">Outflow</p>
           <h3 className="text-3xl font-black text-slate-900 dark:text-white mb-2">${user.monthlyExpense.toLocaleString()}</h3>
           <p className="text-slate-500 text-xs font-bold">Within projected budget</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white dark:bg-slate-800 rounded-[2.5rem] shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col min-h-[500px] overflow-hidden">
          <div className="p-8 border-b border-slate-100 dark:border-slate-700 flex flex-col sm:flex-row justify-between gap-4">
             <h3 className="font-black text-slate-900 dark:text-white text-lg">Activity History</h3>
             <div className="flex gap-2">
                <select value={filterCategory} onChange={(e) => setFilterCategory(e.target.value)} className="px-3 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl text-xs font-bold outline-none">
                   <option value="All">Categories</option>
                   {Object.values(TransactionCategory).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <input type="text" placeholder="Search..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="px-3 py-2 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl text-xs font-bold outline-none w-32 sm:w-48" />
             </div>
          </div>
          <div className="divide-y divide-slate-50 dark:divide-slate-700 flex-1 overflow-y-auto">
            {sortedTransactions.length > 0 ? (
              sortedTransactions.slice(0, 10).map(tx => (
                <TransactionRow 
                  key={tx.id} 
                  transaction={tx} 
                  onClick={() => onNavigateReceipt(tx.id)}
                  onUpdateNote={onUpdateNote}
                />
              ))
            ) : (
              <div className="p-20 text-center text-slate-400">No transactions match your search.</div>
            )}
          </div>
          {onViewAll && (
            <button onClick={onViewAll} className="p-4 bg-slate-50 dark:bg-slate-900/50 text-brand-600 font-black text-xs uppercase tracking-widest hover:text-brand-700">View Comprehensive Statement</button>
          )}
        </div>

        <div className="bg-white dark:bg-slate-800 rounded-[2.5rem] shadow-sm border border-slate-100 dark:border-slate-700 p-8 flex flex-col">
          <h3 className="font-black text-slate-900 dark:text-white mb-8">Spending Analytics</h3>
          <div className="flex-1 min-h-[250px]"><SpendingChart /></div>
          <div className="mt-8 space-y-6">
             <div className="p-4 bg-slate-50 dark:bg-slate-900/50 rounded-2xl border border-slate-100 dark:border-slate-700">
                <div className="flex justify-between mb-2">
                   <span className="text-[10px] font-black uppercase text-slate-400">Weekly Ceiling</span>
                   <span className="text-xs font-black text-slate-900 dark:text-white">65% ($700 remaining)</span>
                </div>
                <div className="h-2 bg-slate-200 dark:bg-slate-700 rounded-full"><div className="h-full bg-brand-500 rounded-full" style={{width: '65%'}}></div></div>
             </div>
          </div>
        </div>
      </div>

      {activeModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-fade-in" onClick={handleCloseModal}>
          <div className="bg-white dark:bg-slate-800 rounded-[2.5rem] shadow-2xl w-full max-w-md p-8 animate-fade-in-up" onClick={e => e.stopPropagation()}>
            <h3 className="text-2xl font-black text-slate-900 dark:text-white mb-6">{activeModal === 'ADD_MONEY' ? 'Deposit Funds' : 'Send Payment'}</h3>
            {!successMsg ? (
              <form onSubmit={activeModal === 'ADD_MONEY' ? handleDeposit : handleTransfer} className="space-y-4">
                {activeModal === 'TRANSFER' && <input type="text" placeholder="Recipient" value={recipient} onChange={e => setRecipient(e.target.value)} required className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-700 rounded-2xl outline-none focus:ring-4 focus:ring-brand-500/10 font-bold" />}
                <div className="relative">
                  <span className="absolute left-5 top-1/2 -translate-y-1/2 font-black text-slate-400">$</span>
                  <input type="number" step="0.01" placeholder="0.00" value={amount} onChange={e => setAmount(e.target.value)} required className="w-full pl-10 pr-5 py-4 bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-700 rounded-2xl outline-none focus:ring-4 focus:ring-brand-500/10 font-black text-xl" />
                </div>
                <button type="submit" disabled={isProcessing} className="w-full bg-brand-600 text-white font-black py-5 rounded-2xl shadow-xl hover:bg-brand-700 transition-all flex justify-center items-center">
                   {isProcessing ? <div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin"></div> : 'Confirm Transaction'}
                </button>
              </form>
            ) : (
              <div className="text-center py-8">
                 <div className="w-20 h-20 bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-full flex items-center justify-center mx-auto mb-6"><svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><polyline points="20 6 9 17 4 12"/></svg></div>
                 <h4 className="text-xl font-bold text-slate-900 dark:text-white mb-2">{successMsg}</h4>
                 <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Processing Reference: {Math.random().toString(36).slice(7).toUpperCase()}</p>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

